BaseSkill = class("BaseSkill")

local uuid = require "base.util.uuid"
uuid.randomseed(os.time())

function BaseSkill:ctor(userId, config)
    self.userId = userId
    self.skillId = config.Id
    self.config = config
    self.skillStage = Define.SkillStage.SkillStart
    self.uuid = uuid()
    self.createTime = os.time()

    LogUtil.log(string.format("BaseSkill:ctor %s %d %s", tostring(userId), config.Id, self.uuid))
end

function BaseSkill:checkThrower()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if player == nil then
        self.skillStage = Define.SkillStage.SkillEnd
    end
    return player
end

function BaseSkill:onTick(ticks)
    if self.skillStage == Define.SkillStage.SkillStart then
        self:onSkillStart(ticks)
    elseif self.skillStage == Define.SkillStage.PlayAnim then
        self:onPlayAnim(ticks)
    elseif self.skillStage == Define.SkillStage.SpecialEffect then
        self:onSpecialEffect(ticks)
    elseif self.skillStage == Define.SkillStage.DoDamage then
        self:onDoDamage(ticks)
    elseif self.skillStage == Define.SkillStage.SkillEnd then
        --TODO
    end
end

